VALUES
  ('elementary-e0adf6cd-moex-00949', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-110-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '教育審議委員會是由直轄市或縣（市）政府所設立，主管該轄內教育事務之審議、諮詢、協調及評鑑等 事宜。該委員會是依據何種法律所成立？', '["國民教育法", "教育基本法", "教育審議條例", "國民及學前教育法"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:42+00:00", "source_pdf_sha1": "f5b0d27260af", "answer_pdf_sha1": "9007eb09ac41", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "504", "s": "0401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00950', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-110-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '甲生在「偏遠地區學校教育發展條例」施行後取得公費生身分，未來將分發至金門的學校任教。關於下 列敘述何者正確？', '["通過教師資格考後不須教育實習直接至該校服務", "服務年限只需依公費生行政契約辦理", "介聘受離島建設條例之規範", "應實際於該校服務5年以上"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:42+00:00", "source_pdf_sha1": "f5b0d27260af", "answer_pdf_sha1": "9007eb09ac41", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "504", "s": "0401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00951', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-110-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '有關原住民族教育法的相關內容，下列敘述何者錯誤？', '["民族教育由原住民族主管機關規劃辦理，並會同教育主管機關為之", "在中央主管機關有二，依性質劃分教育部及原住民族委員會", "原住民族教育政策會之組成，具原住民身分者不得少於三分之一", "預算比率合計不得少於中央教育主管機關預算總額百分之一點九，並依其需求逐年成長"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:42+00:00", "source_pdf_sha1": "f5b0d27260af", "answer_pdf_sha1": "9007eb09ac41", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "504", "s": "0401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00952', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-110-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '「教師輔導與管教學生辦法」於民國92年10月16日廢止，廢止此法之程序為何？', '["教育部發布廢止", "行政院發布廢止", "立法院通過廢止", "經立法院通過，總統發布廢止"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:42+00:00", "source_pdf_sha1": "f5b0d27260af", "answer_pdf_sha1": "9007eb09ac41", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "504", "s": "0401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00953', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-110-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '下列何項教育法規的位階最高？', '["教育人員任用條例", "校園霸凌防制準則", "國立高級中等學校教師每週教學節數標準", "高級中等以下學校及幼稚園教師資格檢定及教育實習辦法"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:42+00:00", "source_pdf_sha1": "f5b0d27260af", "answer_pdf_sha1": "9007eb09ac41", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "504", "s": "0401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00954', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-110-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '某高中學生不服該校對其記過處分，有關學生申訴評議委員會的規定下列何者正確？', '["申訴人提起申訴者，應自知悉之次日起20日內，以書面向學校為之", "學校為處理申訴人申訴案件，應設學生申訴評議委員會，置委員7人至13人，任期一年，均為無給職", "學生申訴評議委員會處理特殊教育學生申訴案件，並應增聘至多 3 位特殊教育學者專家、特殊教育家 長團體代表或其他特殊教育專業人員擔任委員", "學校學生獎懲委員會委員，不得兼任同校學生申訴評議委員會委員"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:42+00:00", "source_pdf_sha1": "f5b0d27260af", "answer_pdf_sha1": "9007eb09ac41", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "504", "s": "0401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00955', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-110-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '依據憲法規定，6歲至12歲之學齡兒童與已逾學齡未受基本教育之國民，二者的規定與保障，下列何者 正確？', '["6歲至12歲之學齡兒童，一律受基本教育；已逾學齡未受基本教育之國民，需接受基本教育", "6歲至12歲之學齡兒童，受基本教育免納學費；已逾學齡未受基本教育之國民，受基本教育需繳納學費", "6歲至12歲之學齡兒童，受基本教育，其書籍均由政府供給", "已逾學齡未受基本教育之國民，受補習教育，免納學費"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:42+00:00", "source_pdf_sha1": "f5b0d27260af", "answer_pdf_sha1": "9007eb09ac41", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "504", "s": "0401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00956', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-110-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '為求能有合宜之班級學生人數及教師員額編制，教育基本法規定中央主管教育行政機關每年應推估未來 幾年之學生及教師人數？', '["3年", "5年", "6年", "10年"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:42+00:00", "source_pdf_sha1": "f5b0d27260af", "answer_pdf_sha1": "9007eb09ac41", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "504", "s": "0401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00957', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-110-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '政府為鼓勵私人興學，得將公立學校委託私人辦理，即所謂學校「公辦民營」，其法源基礎為何？', '["國民教育法", "私立學校法", "學校型態實驗教育實施條例", "教育基本法"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:42+00:00", "source_pdf_sha1": "f5b0d27260af", "answer_pdf_sha1": "9007eb09ac41", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "504", "s": "0401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00958', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-110-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '蔡同學因感染流行性感冒，向學校請假故不能參加就讀國中的定期評量，依國民小學及國民中學成績評 量準則，學校應如何計算蔡同學補行評量之成績？', '["實得分數低於60分者以實得分數計，實得分數高於或等於60分者以60分計", "依其實得分數乘以百分之九十", "依其實得分數乘以百分之八十", "依其實得分數計算"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:42+00:00", "source_pdf_sha1": "f5b0d27260af", "answer_pdf_sha1": "9007eb09ac41", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "504", "s": "0401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL)
